// Logout
app.post('/auth/logout', (req, res) => {
  const userId = req.session.userId;

  if (userId) {
    removeCode(userId);
  }

  req.session.destroy((err) => {
    if (err) {
      return res.status(500).json({
        success: false,
        message: 'Failed to logout.'
      });
    }
    res.clearCookie('connect.sid');
    res.json({
      success: true,
      message: 'Logged out successfully.'
    });
  });
});

// Get authentication status
app.get('/auth/status', (req, res) => {
  res.json({
    authenticated: !!(req.session.userId && req.session.twoFactorVerified),
    passwordVerified: !!req.session.passwordVerified,
    twoFactorVerified: !!req.session.twoFactorVerified,
    userId: req.session.userId || null
  });
});

// Register a new user (for testing purposes)
app.post('/auth/register', (req, res) => {
  const { username, password, phone } = req.body;

  if (!username || !password || !phone) {
    return res.status(400).json({
      success: false,
      message: 'Username, password, and phone number are required.'
    });
  }

  // Validate phone number format (basic E.164 validation)
  if (!/^\+[1-9]\d{1,14}$/.test(phone)) {
    return res.status(400).json({
      success: false,
      message: 'Invalid phone number format. Use E.164 format (e.g., +11234567890).'
    });
  }

  // Check if username already exists
  for (const [, user] of users.entries()) {
    if (user.username === username) {
      return res.status(409).json({
        success: false,
        message: 'Username already exists.'
      });
    }
  }

  const userId = `user_${Date.now()}`;
  // In production, hash the password with bcrypt
  users.set(userId, {
    id: userId,
    username,
    phone,
    password // Should be bcrypt.hashSync(password, 10) in production
  });

  res.status(201).json({
    success: true,
    message: 'User registered successfully.',
    user: {
      id: userId,
      username,
      phone: maskPhoneNumber(phone)
    }
  });
});

